                <SelectItem value="receita">Receita</SelectItem>
                <SelectItem value="despesa">Despesa</SelectItem>
                <SelectItem value="reembolso">Reembolso</SelectItem>
                <SelectItem value="solicitacao_recurso">Solicitação</SelectItem>
