                </CardHeader>
                <CardContent>
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-4 text-sm">
                    <div>
                      <p className="text-muted-foreground">Vigência:</p>
                      <p className="font-medium" data-testid={`text-vigencia-${contrato.id}`}>
