                    </div>
                    <div>
                      <p className="text-muted-foreground">Aditivos:</p>
                      <p className="font-medium" data-testid={`text-aditivos-count-${contrato.id}`}>
                        {contrato.aditivos?.length || 0}
                      </p>
                    </div>
                  </div>
                </CardContent>
              </Card>

              {/* Aditivos */}
              <Card>
                <CardHeader>
                  <div className="flex justify-between items-center">
