              <CardContent className="space-y-2">
                <p className="text-sm text-muted-foreground line-clamp-2">{dataset.descricao}</p>

                <div className="flex items-center justify-between text-xs">
                  <span className="text-muted-foreground">
                    <span className="font-medium">Tipo:</span> {dataset.tipo}
                  </span>
                  <Badge variant="secondary" className="text-xs">
                    {formatFileSize(dataset.tamanho)}
                  </Badge>
                </div>

                <div className="flex items-center justify-between text-xs">
                  <span className="text-muted-foreground">
                    <span className="font-medium">Upload:</span>{" "}
                    {new Date(dataset.dataUpload).toLocaleDateString("pt-BR")}
                  </span>
                </div>

                <div className="flex items-center justify-between text-xs">
                  <span className="text-muted-foreground">
                    <span className="font-medium">Por:</span> {dataset.uploadedBy}
                  </span>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}

      {datasets.length > 8 && (
        <div className="text-center">
